arguments.file_text:
namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public required string Code { get; set; }
    public required string Name { get; set; }
    public required string Description { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public required string Code { get; set; }
    public required string Title { get; set; }
    public required string Description { get; set; }
    public int Credits { get; set; }
    public required string Schedule { get; set; }
    public required string InstructorName { get; set; }
    public required string InstructorBio { get; set; }
    public int DepartmentId { get; set; }
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100, ErrorMessage = "Name cannot exceed 100 characters.")]
    public string FullName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Za-z0-9]{5,15}$", ErrorMessage = "Student ID must be 5–15 alphanumeric characters.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments =
        [
            new() { Id = 1, Code = "CS",   Name = "Computer Science",        Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics",             Description = "Pure and applied mathematics, statistics, and data analysis." },
            new() { Id = 3, Code = "ENG",  Name = "English",                 Description = "Literature, writing, and critical analysis of texts." },
            new() { Id = 4, Code = "PHYS", Name = "Physics",                 Description = "Fundamental laws of nature, mechanics, and modern physics." },
            new() { Id = 5, Code = "HIST", Name = "History",                 Description = "World civilizations, political movements, and cultural change." },
            new() { Id = 6, Code = "BIO",  Name = "Biology",                 Description = "Life sciences, genetics, ecology, and cellular biology." },
        ];

        _courses =
        [
            // Computer Science
            new() { Id = 1,  Code = "CS 101",   Title = "Introduction to Programming",    Description = "Foundational programming concepts using Python. Covers variables, control flow, functions, and basic data structures. Ideal for students with no prior coding experience.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM",  InstructorName = "Dr. Alice Chen",      InstructorBio = "Ph.D. in Computer Science from MIT. Specializes in programming education and has authored two introductory textbooks.", DepartmentId = 1, IsFeatured = true },
            new() { Id = 2,  Code = "CS 201",   Title = "Data Structures & Algorithms",   Description = "In-depth study of data organization, searching, sorting, trees, graphs, and algorithm analysis. Prerequisites: CS 101.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM",    InstructorName = "Dr. Bob Martinez",    InstructorBio = "Former software engineer at Google. Research focus on algorithm optimization and competitive programming.", DepartmentId = 1 },
            new() { Id = 3,  Code = "CS 310",   Title = "Database Systems",                Description = "Relational database design, SQL, normalization, indexing, and an introduction to NoSQL systems.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM",        InstructorName = "Dr. Alice Chen",      InstructorBio = "Ph.D. in Computer Science from MIT. Specializes in programming education and has authored two introductory textbooks.", DepartmentId = 1 },

            // Mathematics
            new() { Id = 4,  Code = "MATH 101", Title = "Calculus I",                      Description = "Limits, derivatives, integrals, and the Fundamental Theorem of Calculus. Covers single-variable calculus with applications.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Carol Liu",       InstructorBio = "Awarded the university's Distinguished Teaching Award three times. Researches numerical analysis.", DepartmentId = 2, IsFeatured = true },
            new() { Id = 5,  Code = "MATH 201", Title = "Linear Algebra",                  Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM",        InstructorName = "Dr. David Park",      InstructorBio = "Published over 40 papers in abstract algebra. Former visiting scholar at Oxford.", DepartmentId = 2 },
            new() { Id = 6,  Code = "MATH 301", Title = "Probability & Statistics",        Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:15 PM",  InstructorName = "Dr. Carol Liu",       InstructorBio = "Awarded the university's Distinguished Teaching Award three times. Researches numerical analysis.", DepartmentId = 2 },

            // English
            new() { Id = 7,  Code = "ENG 101",  Title = "Academic Writing",                Description = "Develops skills in thesis construction, argumentation, research methods, and academic citation styles.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM",      InstructorName = "Prof. Emily Torres",  InstructorBio = "MFA from the Iowa Writers' Workshop. Published essayist and writing pedagogy researcher.", DepartmentId = 3, IsFeatured = true },
            new() { Id = 8,  Code = "ENG 220",  Title = "American Literature",             Description = "Survey of American literary works from the colonial period through the 21st century.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM",    InstructorName = "Dr. Frank Okafor",    InstructorBio = "Specialist in African-American literature and cultural criticism. Author of 'Voices Unheard.'", DepartmentId = 3 },

            // Physics
            new() { Id = 9,  Code = "PHYS 101", Title = "General Physics I",               Description = "Newtonian mechanics, energy, momentum, rotational dynamics, and wave motion. Includes weekly lab sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Grace Kim",       InstructorBio = "Experimental physicist with research in optics and photonics. Previously at Fermilab.", DepartmentId = 4 },
            new() { Id = 10, Code = "PHYS 201", Title = "Electromagnetism",                Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 2:30–3:45 PM",        InstructorName = "Dr. Henry Walsh",     InstructorBio = "Theoretical physicist studying quantum electrodynamics. 20 years of teaching experience.", DepartmentId = 4, IsFeatured = true },

            // History
            new() { Id = 11, Code = "HIST 101", Title = "World Civilizations I",           Description = "Survey of global history from prehistoric times through the Renaissance. Covers major civilizations and cross-cultural exchange.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", InstructorName = "Dr. Isabel Reyes",    InstructorBio = "Historian of early modern Europe with a focus on trade networks and cultural diffusion.", DepartmentId = 5 },
            new() { Id = 12, Code = "HIST 250", Title = "Modern U.S. History",             Description = "The United States from Reconstruction to the present, focusing on social movements, politics, and cultural change.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM",       InstructorName = "Dr. James Whitfield", InstructorBio = "Civil rights era scholar and oral history practitioner. Advisor to the National Archives.", DepartmentId = 5 },

            // Biology
            new() { Id = 13, Code = "BIO 101",  Title = "Introduction to Biology",        Description = "Cell structure, genetics, evolution, and ecology. Includes hands-on laboratory exercises each week.", Credits = 4, Schedule = "Mon/Wed/Fri 8:00–8:50 AM",  InstructorName = "Dr. Karen Patel",     InstructorBio = "Microbiologist with NIH-funded research in antimicrobial resistance. Passionate about undergraduate mentorship.", DepartmentId = 6, IsFeatured = true },
            new() { Id = 14, Code = "BIO 210",  Title = "Genetics",                        Description = "Mendelian and molecular genetics, gene expression, regulation, and modern genomic technologies.", Credits = 3, Schedule = "Tue/Thu 3:00–4:15 PM",       InstructorName = "Dr. Leo Nakamura",    InstructorBio = "Genomics researcher focused on CRISPR applications. Published in Nature Genetics.", DepartmentId = 6 },
        ];
    }

    public IReadOnlyList<Department> GetAllDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.Find(d => d.Id == id);

    public Department? GetDepartmentByCode(string code) =>
        _departments.Find(d => d.Code.Equals(code, StringComparison.OrdinalIgnoreCase));

    public IReadOnlyList<Course> GetAllCourses() => _courses;

    public IReadOnlyList<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.Find(c => c.Id == id);

    public IReadOnlyList<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        IEnumerable<Course> results = _courses;

        if (departmentId.HasValue && departmentId.Value > 0)
            results = results.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            results = results.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return results.ToList();
    }

    public IReadOnlyList<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();
}

