    public IReadOnlyList<Department> GetAllDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.Find(d => d.Id == id);

    public Department? GetDepartmentByCode(string code) =>
        _departments.Find(d => d.Code.Equals(code, StringComparison.OrdinalIgnoreCase));

    public IReadOnlyList<Course> GetAllCourses() => _courses;

    public IReadOnlyList<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.Find(c => c.Id == id);

    public IReadOnlyList<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        IEnumerable<Course> results = _courses;

        if (departmentId.HasValue && departmentId.Value > 0)
            results = results.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            results = results.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return results.ToList();
    }

    public IReadOnlyList<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();
}

