                    <p class="card-text">@course.InstructorBio</p>
                </div>
            </div>

            <div class="mt-3">
                <a href="@($"enroll?courseId={course.Id}")" class="btn btn-success w-100">Enroll in this Course</a>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Submit Enrollment Request</h1>
<p>Fill out the form below to request enrollment in a course.</p>

@if (Submitted)
{
    var selectedCourse = Catalog.GetCourse(Model.CourseId);
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@Model.FullName</strong> (ID: @Model.StudentId). Your enrollment request for
        <strong>@selectedCourse?.Code — @selectedCourse?.Title</strong> has been received.</p>
        <hr />
        <p class="mb-0">You will receive a confirmation via your university email.</p>
    </div>
    <a href="enroll" class="btn btn-primary">Submit Another Request</a>
}
else
{
    <EditForm method="post" Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" class="mt-3">
        <DataAnnotationsValidator />
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="fullName" class="form-label">Full Name</label>
            <InputText id="fullName" @bind-Value="Model.FullName" class="form-control" />
            <ValidationMessage For="() => Model.FullName" />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" />
            <ValidationMessage For="() => Model.StudentId" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-select">
                <option value="0">— Select a course —</option>
                @foreach (var course in Catalog.GetAllCourses())
                {
                    <option value="@course.Id">@course.Code — @course.Title</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.CourseId" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private bool Submitted { get; set; }

    protected override void OnInitialized()
    {
        if (CourseId.HasValue && CourseId.Value > 0 && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        Submitted = true;
    }
}

